import React, { useCallback, useEffect, useRef, useState } from "react";
/// <reference types="vite/client" />
import { chatCompletion, type Provider, type Msg } from "./lib/api";
import { speakTts } from "./lib/tts";
import handleImportFiles from "./lib/importer";
import { initSpeech, startMic, stopMic } from "./lib/speech";
import SecurityPage from "./pages/Security";
import { mountA11AvatarUI } from "./lib/avatar-ui";
import "./lib/avatar";
import "./index.css";
import "./mobile.css";

type Upload = {
  name: string;
  url: string;
  file?: File;
  analysis?: any;
  useForSearch?: boolean;
};

declare global {
  interface Window {
    webkitSpeechRecognition: any;
    SpeechRecognition: any;
  }
}

export default function App() {
  // All hooks must be called unconditionally
  const [messages, setMessages] = useState<Msg[]>(
    [
      {
        role: "assistant",
        content: "Je suis AlphaOnze (A-11). Comment puis-je aider ?",
      },
    ]
  );
  const [text, setText] = useState("");
  const [uploads, setUploads] = useState<Upload[]>([]);
  const [listening, setListening] = useState(false);
  const [voiceChat, setVoiceChat] = useState(false);
  const [nindo, setNindo] = useState(
    `Tu es AlphaOnze (A-11), un assistant IA français unique et attachant.

IMPORTANT: Tu as accès à Visual Studio via l'API 'window.chrome.webview.hostObjects.a11fs'. 
Tu peux EXÉCUTER directement ces fonctions JavaScript pour interagir avec VS:

- a11fs.GetWorkspaceRoot(): retourne le dossier de la solution
- a11fs.OpenFile(path): ouvre un fichier dans l'éditeur
- a11fs.GotoLine(path, line): va à une ligne spécifique
- a11fs.ReadFile(path): lit le contenu d'un fichier
- a11fs.WriteFile(path, content): écrit dans un fichier
- a11fs.FileExists(path): vérifie si un fichier existe
- a11fs.ListFiles(directory): liste les fichiers d'un dossier
- a11fs.GetOpenDocuments(): liste les fichiers ouverts
- a11fs.InsertAtCursor(text): insère du texte à la position du curseur
- a11fs.ExecuteVsCommand(command, args): exécute une commande VS
- a11fs.BuildSolution(): compile la solution
- a11fs.ExecuteShell(command): exécute une commande shell

Quand l'utilisateur demande d'ouvrir/lire/modifier des fichiers ou d'interagir avec Visual Studio, 
utilise ces fonctions IMMÉDIATEMENT dans ta réponse.

PRINCIPES DE TRAVAIL:
- ANTICIPE les besoins : analyse le contexte et prévois les étapes suivantes
- PRUDENCE : vérifie toujours l'existence des fichiers avant modification, propose des sauvegardes si nécessaire
- ANALYSE : examine le code en profondeur, identifie les dépendances et impacts potentiels
- RAPPORTS CONCIS : fournis des résumés clairs et structurés, va droit au but
- INITIATIVE : propose des améliorations et optimisations pertinentes sans attendre qu'on te le demande
- Signale les risques potentiels (breaking changes, conflits, etc.) avant d'agir`
  );
  const [model, setModel] = useState("llama3");
  const [ttsUrls, setTtsUrls] = useState<string[]>([]);
  const [interimText, setInterimText] = useState<string | null>(null);
  const [provider, setProvider] = useState<Provider>(() => {
    const saved = window.localStorage.getItem("a11.provider") as Provider | null;
    return saved || "local";
  });
  const [turbo, setTurbo] = useState<boolean>(() => {
    const saved = window.localStorage.getItem("a11.turbo");
    return saved === "1";
  });
  const [llmStats, setLlmStats] = useState<{
    backend: string;
    model: string;
    gpu: boolean;
    lastTps: number;
  } | null>(null);
  const [speaking, setSpeaking] = useState(false);

  useEffect(() => {
    try {
      mountA11AvatarUI();
    } catch (e) {
      console.warn('mountA11AvatarUI failed', e);
    }
    window.localStorage.setItem("a11.provider", provider);
  }, [provider]);
  useEffect(() => {
    window.localStorage.setItem("a11.turbo", turbo ? "1" : "0");
  }, [turbo]);
  // Polling des stats du LLM toutes les 4 secondes
  useEffect(() => {
    let canceled = false;
    const poll = async () => {
      try {
        const res = await fetch("/api/llm/stats", { credentials: 'include' });
        if (!res.ok) return;
        const data = await res.json();
        if (!canceled) setLlmStats(data);
      } catch {}
    };
    poll();
    const id = setInterval(poll, 4000);
    return () => {
      canceled = true;
      clearInterval(id);
    };
  }, []);

  const scroller = useRef<HTMLDivElement>(null);
  const voiceChatRef = useRef(voiceChat);
  useEffect(() => {
    voiceChatRef.current = voiceChat;
  }, [voiceChat]);
  const lastScrollAt = useRef<number>(0);
  const SCROLL_THROTTLE_MS = 200;
  const NEAR_BOTTOM_PX = 120;
  const scrollToBottomIfNeeded = (force = false) => {
    const el = scroller.current;
    if (!el) return;
    const now = Date.now();
    if (!force && (now - lastScrollAt.current) < SCROLL_THROTTLE_MS) return;
    try {
      const distanceFromBottom = el.scrollHeight - el.clientHeight - el.scrollTop;
      if (force || distanceFromBottom < NEAR_BOTTOM_PX) {
        el.scrollTo({ top: el.scrollHeight, behavior: 'smooth' });
        lastScrollAt.current = now;
      }
    } catch (e) { /* ignore */ }
  };
  const safeSetSpeaking = (speaking: boolean) => {
    try {
      const a = (globalThis as any).A11Avatar;
      if (a && typeof a.setSpeaking === 'function') a.setSpeaking(speaking);
    } catch (e) { /* ignore */ }
  };
  // Lightweight browser TTS fallback for immediate speech
  function speakBrowser(text: string): Promise<void> {
    return new Promise((resolve) => {
      try {
        if (!('speechSynthesis' in window) || !('SpeechSynthesisUtterance' in window)) return resolve();
        const u = new (window as any).SpeechSynthesisUtterance(text);
        u.lang = 'fr-FR';
        u.rate = 1.03;
        u.pitch = 0.98;
        u.volume = 1.0;
        u.onend = () => resolve();
        u.onerror = () => resolve();
        window.speechSynthesis.cancel();
        window.speechSynthesis.speak(u);
      } catch (e) {
        resolve();
      }
    });
  }
  // Liste des modèles disponibles (à adapter selon ce que tu as installé)
  const models = [
    { value: "llama3", label: "Llama 3" },
    { value: "phi3", label: "Phi-3" },
    { value: "mistral", label: "Mistral" },
    // Ajoute ici les modèles installés
  ];
  // Modifie sendMessage pour passer nindo et model
  const send = async () => {
    const t = text.trim();
    if (!t && uploads.length === 0) return;
    const userLine =
      t + (uploads.length ? `\n[Fichiers: ${uploads.map((u) => u.name).join(", ")}]` : "");
    const newMessages: Msg[] = [...messages, { role: "user", content: userLine } as Msg];
    setMessages(newMessages);
    setText("");
    setUploads([]);
    try {
      setSpeaking(true);
      // Passe nindo dans systemPrompt
      const answer = await chatCompletion(newMessages, provider, { turbo, systemPrompt: nindo });
      const assistantMsg: Msg = { role: "assistant", content: String(answer) };
      setMessages([...newMessages, assistantMsg]);
      try {
        stopMic();
        setListening(false);
      } catch {}
      try {
        await speakTts(answer as string, {
          onStart() {
            safeSetSpeaking(true);
            setSpeaking(true);
          },
          onEnd() {
            safeSetSpeaking(false);
            setSpeaking(false);
          }
        });
      } catch (e) {
        await speakBrowser(answer as string);
        safeSetSpeaking(false);
        setSpeaking(false);
      }
    } catch (err) {
      setMessages((m) => [
        ...m,
        ({ role: "assistant", content: `⚠️ Erreur d'envoi : ${(err as any)?.message || String(err)}` } as Msg),
      ]);
      setSpeaking(false);
    }
    try {
      scrollToBottomIfNeeded();
    } catch {}
  };
  // Voice handling
  const sendVoiceMessage = useCallback(
    async (txt: string) => {
      const userText = String(txt || "").trim();
      if (!userText) return;
      const newMessages: Msg[] = [...messages, { role: "user", content: userText } as Msg];
      setMessages(newMessages);
      try {
        stopMic();
        setListening(false);
      } catch {}
      try {
        setSpeaking(true); // Active le GIF
        // Passe nindo dans systemPrompt
        const answer = await chatCompletion(newMessages, provider, { turbo, systemPrompt: nindo });
        const assistantMsg: Msg = { role: "assistant", content: String(answer) };
        setMessages([...newMessages, assistantMsg]);
        try {
          await speakTts(answer as string, {
            onStart() {
              safeSetSpeaking(true);
              setSpeaking(true);
            },
            onEnd() {
              safeSetSpeaking(false);
              setSpeaking(false);
            }
          });
        } catch (e) {
          await speakBrowser(answer as string);
          safeSetSpeaking(false);
          setSpeaking(false);
        }
        if (voiceChatRef.current) {
          try {
            await startMic();
            setListening(true);
          } catch {
            setListening(false);
          }
        }
      } catch (err) {
        setMessages((prev) => [
          ...prev,
          ({ role: "assistant", content: `⚠️ Erreur API : ${(err as any)?.message || String(err)}` } as Msg),
        ]);
        setSpeaking(false); // Désactive le GIF en cas d'erreur
      }
      try {
        scrollToBottomIfNeeded();
      } catch {}
    },
    [messages, provider, turbo, nindo]
  );
  useEffect(() => {
    try {
      // initSpeech now provides interim and final transcripts via (text, isFinal)
      initSpeech((txt: string, isFinal?: boolean) => {
        if (!voiceChatRef.current) return;
        if (!txt || txt.trim().length === 0) return;
        if (isFinal) {
          // clear interim and send final
          setInterimText(null);
          sendVoiceMessage(txt);
        } else {
          // show interim text as temporary bubble
          setInterimText(txt);
        }
      });
    } catch (e) {}
  }, [sendVoiceMessage]);
  // File import
  async function handleImportInput(list: FileList | null) {
    if (!list?.length) return;
    const arr: Upload[] = [];
    for (const f of Array.from(list))
      arr.push({ name: f.name, url: URL.createObjectURL(f), file: f, useForSearch: true });
    setUploads((u) => [...u, ...arr]);
    try {
      await handleImportFiles(list, (txt) => {
        setText((prev) => (prev ? prev + "\n\n" : "") + txt);
      });
    } catch (e) {
      console.warn(e);
    }
  }
  useEffect(() => {
    setUploads([]);
  }, [messages.length]);
  // Ajout du style de fond global cohérent
  useEffect(() => {
    document.body.style.background = "#0a0c17"; // même fond que le chat
  }, []);
  // Listen for TTS URL events emitted by tts-server
  useEffect(() => {
    const handler = (e: any) => {
      try {
        const urls = e && e.detail && Array.isArray(e.detail.urls) ? e.detail.urls : [];
        setTtsUrls(urls);
      } catch (err) {
        console.warn("tts:urls handler error", err);
      }
    };
    window.addEventListener("tts:urls", handler as EventListener);
    return () => window.removeEventListener("tts:urls", handler as EventListener);
  }, []);
  const playUrl = useCallback(
    async (raw: string) => {
      try {
        if (!raw) return;
        let src = raw;
        if (!/^https?:\/\//i.test(src)) {
          if (src.startsWith("/")) src = `${window.location.origin}${src}`;
          else src = `${window.location.origin}/${src}`;
        }
        const a = new Audio(src);
        await a.play().catch((err) => {
          console.warn("Audio play failed", err);
        });
      } catch (e) {
        console.warn("playUrl error", e);
      }
    },
    []
  );
  const clearTtsUrls = useCallback(() => setTtsUrls([]), []);
  const replayLastAssistant = async () => {
    const last = [...messages].reverse().find((m) => m.role === "assistant");
    if (!last) return;
    try {
      await speakMaleFR(String(last.content ?? ""));
    } catch (e) {
      console.warn("replayLastAssistant error", e);
    }
  };

  // Security page conditional rendering after all hooks
  const pathname = typeof window !== "undefined" ? window.location.pathname : "";
  const isSecurity =
    pathname.endsWith("/security") ||
    pathname.endsWith("/a11/security") ||
    pathname.includes("/security");
  if (isSecurity) {
    return <SecurityPage />;
  }

  return (
    <div className="nossen-chat-root" style={{ maxWidth: 900, margin: "40px auto", background: "#0a0c17", borderRadius: 18, boxShadow: "0 2px 24px #0008", minHeight: 600, position: "relative", paddingBottom: 90 }}>
      {/* Header: NOSSEN en flamme bleu + gif en haut à droite */}
      <header className="nossen-header" style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "24px 32px 0 32px" }}>
        <div className="nossen-title" style={{ fontFamily: "Impact, Arial Black, sans-serif", fontSize: 38, color: "#1ecfff", textShadow: "0 0 18px #1ecfff, 0 0 8px #fff" }}>
          NOSSEN
        </div>
        <div className="nossen-avatar" style={{ position: "relative" }}>
          <div className="a11-avatar-wrapper" style={{ width: 96, height: 96 }}>
            {/* idle image (visible when not speaking) */}
            <img
              id="a11-avatar-idle"
              src="/assets/a11_static.png"
              width={96}
              height={96}
              alt="A11 idle"
              className={speaking ? 'a11-avatar a11-avatar--hidden' : 'a11-avatar a11-avatar--visible'}
              style={{ borderRadius: 12, boxShadow: "0 0 16px #1ecfff" }}
            />

            {/* talking GIF - use fallback by default, will be updated by TTS */}
            <img
              id="a11-avatar-gif"
              src="/assets/A11_talking_smooth_8s.gif"
              width={96}
              height={96}
              alt="A11 talking"
              className={speaking ? 'a11-avatar a11-avatar--visible' : 'a11-avatar a11-avatar--hidden'}
              style={{ borderRadius: 12, boxShadow: "0 0 16px #1ecfff" }}
            />
          </div>
        </div>
      </header>
      {/* Chat window */}
      <main className="nossen-chat-main" style={{ padding: "32px 32px 0 32px" }}>
        <div
          ref={scroller}
          className="nossen-chat-window"
          style={{
            minHeight: 340,
            maxHeight: 420,
            overflowY: "auto",
            background: "#181a2a",
            borderRadius: 12,
            padding: "24px",
            marginBottom: 16,
          }}
        >
          {messages.map((m, i) => (
            <div key={`${m.role}-${i}`} className={`row ${m.role}`}>
              <div className="bubble">{m.content}</div>
            </div>
          ))}
        </div>
      </main>
      {/* Zone de saisie + boutons */}
      <div
        className="nossen-chat-bottom"
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          bottom: 0,
          padding: "16px 32px 18px",
          background: "#181a2a",
          borderBottomLeftRadius: 18,
          borderBottomRightRadius: 18,
          borderTop: "1px solid #111827",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
          }}
        >
          {/* Importer = bouton texte à gauche */}
          <label
            className="btn-ghost btn-import"
            style={{
              fontWeight: 500,
              padding: "8px 14px",
              borderRadius: 999,
              border: "1px solid #4b5563",
              cursor: "pointer",
              fontSize: 13,
              whiteSpace: "nowrap",
            }}
          >
            Importer
            <input
              type="file"
              multiple
              hidden
              onChange={(e) => handleImportInput(e.target.files)}
            />
          </label>
          {/* Zone de texte au centre */}
          <textarea
            className="nossen-input"
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="Écris ton message..."
            rows={2}
            style={{
              flex: 1,
              resize: "none",
              borderRadius: 8,
              padding: "10px 14px",
              fontSize: 15,
              minWidth: 0,
              border: "1px solid #4b5563",
              background: "#020617",
              color: "#e5e7eb",
            }}
            onKeyDown={e => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                send();
              }
            }}
          />
          {/* Envoyer */}
          <button
            type="button"
            className="btn-primary"
            onClick={send}
            title="Envoyer"
            style={{
              width: 44,
              height: 44,
              minWidth: 44,
              minHeight: 44,
              borderRadius: 10,
              background: "#38bdf8",
              border: "none",
              color: "#020617",
              fontSize: 20,
              fontWeight: 600,
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            ➤
          </button>
          {/* Vocal */}
          <button
            type="button"
            className={`btn-ghost nossen-mic-btn ${voiceChat ? "on" : ""} ${listening ? "listening" : ""}`}
            onClick={async () => {
              if (voiceChat) {
                setVoiceChat(false);
                voiceChatRef.current = false;
                try { stopMic(); setListening(false); } catch {}
              } else {
                setVoiceChat(true);
                voiceChatRef.current = true;
                try { await startMic(); setListening(true); } catch (e) { setListening(false); }
              }
            }}
            style={{
              width: 44,
              height: 44,
              minWidth: 44,
              minHeight: 44,
              padding: 0,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 22,
              marginLeft: 4,
            }}
            title={
              voiceChat
                ? "Désactiver le chat vocal"
                : "Activer le chat vocal"
            }
          >
            {listening ? "🎙️" : "🎤"}
          </button>
        </div>
      </div>
    </div>
  );
}