/**
 * Helper pour gérer la lecture vocale (TTS) avec interruption automatique
 * Supporte: TTS navigateur (fallback) + TTS backend (Piper supervisé)
 * Usage: appeler speak(text) pour lire, cancelSpeech() pour interrompre
 */

let currentUtterance: SpeechSynthesisUtterance | null = null;
let currentAudio: HTMLAudioElement | null = null;
let recognition: any = null;
let micActive: boolean = false;
let speechInitialized: boolean = false;

// Configuration TTS backend (safe access to Vite env vars)
const TTS_BACKEND_URL = (typeof window !== 'undefined' && (window as any).VITE_TTS_BACKEND_URL) || 'http://127.0.0.1:3000/api/tts';
const USE_BACKEND_TTS = (typeof window !== 'undefined' && (window as any).VITE_USE_BACKEND_TTS) !== 'false';

// Log configuration au démarrage (une seule fois)
if (typeof window !== 'undefined' && !speechInitialized) {
  console.log('[speech] 🎤 Configuration TTS:', {
    backend_url: TTS_BACKEND_URL,
    use_backend: USE_BACKEND_TTS,
    browser_tts: !!window.speechSynthesis,
    webview2: !!(window as any).chrome?.webview
  });
}

/**
 * Interrompt toute lecture vocale en cours
 */
export function cancelSpeech(): void {
  // Cancel browser TTS
  if (window.speechSynthesis) {
    window.speechSynthesis.cancel();
    currentUtterance = null;
  }

  // Cancel backend audio
  if (currentAudio) {
    currentAudio.pause();
    currentAudio.src = '';
    currentAudio = null;
  }

  console.log('[speech] ⏹️ Lecture vocale interrompue');
}

/**
 * Lit un texte via le backend TTS (Piper supervisé)
 */
async function speakBackend(
  text: string,
  options: {
    voice?: string;
    provider?: string;
    onEnd?: () => void;
    onError?: (error: Error) => void;
  } = {}
): Promise<boolean> {
  try {
    const response = await fetch(`${TTS_BACKEND_URL}/speak`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        text,
        voice: options.voice || 'fr_FR-siwis-medium',
        provider: options.provider || 'piper'
      })
    });

    if (!response.ok) {
      throw new Error(`TTS backend error: ${response.status}`);
    }

    // Response is audio/wav
    const blob = await response.blob();
    const url = URL.createObjectURL(blob);

    const audio = new Audio(url);
    currentAudio = audio;

    audio.onended = () => {
      URL.revokeObjectURL(url);
      currentAudio = null;
      console.log('[speech] ✅ Lecture backend terminée');
      options.onEnd?.();
    };

    audio.onerror = (event) => {
      URL.revokeObjectURL(url);
      currentAudio = null;
      console.error('[speech] ❌ Erreur lecture backend:', event);
      options.onError?.(new Error('Backend audio playback error'));
    };

    await audio.play();
    console.log('[speech] 🔊 Lecture backend démarrée (Piper)');
    return true;
  } catch (err) {
    console.error('[speech] ❌ Backend TTS failed:', err);
    options.onError?.(err as Error);
    return false;
  }
}

/**
 * Lit un texte via le navigateur (fallback)
 */
function speakBrowser(
  text: string,
  options: {
    lang?: string;
    rate?: number;
    pitch?: number;
    volume?: number;
    onEnd?: () => void;
    onError?: (error: Error) => void;
  } = {}
): void {
  if (!window.speechSynthesis) {
    console.warn('[speech] ⚠️ SpeechSynthesis API non disponible');
    options.onError?.(new Error('SpeechSynthesis not available'));
    return;
  }

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = options.lang || 'fr-FR';
  utterance.rate = options.rate || 1.0;
  utterance.pitch = options.pitch || 1.0;
  utterance.volume = options.volume || 1.0;

  utterance.onend = () => {
    currentUtterance = null;
    console.log('[speech] ✅ Lecture navigateur terminée');
    options.onEnd?.();
  };

  utterance.onerror = (event) => {
    currentUtterance = null;
    console.error('[speech] ❌ Erreur lecture navigateur:', event);
    options.onError?.(new Error(event.error));
  };

  currentUtterance = utterance;
  window.speechSynthesis.speak(utterance);
  console.log('[speech] 🔊 Lecture navigateur démarrée');
}

/**
 * Lit un texte à voix haute (interrompt automatiquement la lecture précédente)
 * Utilise le backend TTS (Piper) si disponible, sinon fallback navigateur
 * @param text Texte à lire
 * @param options Options de synthèse vocale
 */
export async function speak(
  text: string,
  options: {
    lang?: string;
    rate?: number;
    pitch?: number;
    volume?: number;
    voice?: string;
    provider?: string;
    useBackend?: boolean;
    onEnd?: () => void;
    onError?: (error: Error) => void;
  } = {}
): Promise<void> {
  // 🔥 INTERROMPRE toute lecture en cours
  cancelSpeech();

  const useBackend = options.useBackend !== false && USE_BACKEND_TTS;

  if (useBackend) {
    console.log('[speech] Tentative TTS backend (Piper)...');
    const success = await speakBackend(text, {
      voice: options.voice,
      provider: options.provider,
      onEnd: options.onEnd,
      onError: (err) => {
        console.warn('[speech] Backend TTS failed, falling back to browser');
        // Fallback to browser on backend error
        speakBrowser(text, options);
      }
    });

    // If backend succeeded, we're done
    if (success) return;
  }

  // Use browser TTS (fallback or explicit)
  console.log('[speech] Utilisation TTS navigateur');
  speakBrowser(text, options);
}

/**
 * Vérifie si une lecture vocale est en cours
 */
export function isSpeaking(): boolean {
  return (
    (window.speechSynthesis?.speaking || false) ||
    (currentAudio !== null && !currentAudio.paused)
  );
}

/**
 * Met en pause la lecture vocale
 */
export function pauseSpeech(): void {
  if (window.speechSynthesis?.speaking) {
    window.speechSynthesis.pause();
    console.log('[speech] ⏸️ Lecture navigateur en pause');
  }
  if (currentAudio && !currentAudio.paused) {
    currentAudio.pause();
    console.log('[speech] ⏸️ Lecture backend en pause');
  }
}

/**
 * Reprend la lecture vocale
 */
export function resumeSpeech(): void {
  if (window.speechSynthesis?.paused) {
    window.speechSynthesis.resume();
    console.log('[speech] ▶️ Lecture navigateur reprise');
  }
  if (currentAudio && currentAudio.paused) {
    currentAudio.play();
    console.log('[speech] ▶️ Lecture backend reprise');
  }
}

/**
 * Récupère la liste des voix disponibles (navigateur uniquement)
 */
export function getVoices(): SpeechSynthesisVoice[] {
  return window.speechSynthesis?.getVoices() || [];
}

/**
 * Trouve une voix par langue (navigateur uniquement)
 * @param lang Code langue (ex: 'fr-FR', 'en-US')
 */
export function findVoiceByLang(lang: string): SpeechSynthesisVoice | null {
  const voices = getVoices();
  return voices.find(v => v.lang === lang) || voices.find(v => v.lang.startsWith(lang.split('-')[0])) || null;
}

/**
 * Test la disponibilité du backend TTS
 */
export async function checkBackendTTS(): Promise<boolean> {
  try {
    const response = await fetch(`${TTS_BACKEND_URL}/speak`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: 'test', provider: 'piper' })
    });
    return response.ok;
  } catch (err) {
    console.warn('[speech] Backend TTS non disponible:', err);
    return false;
  }
}

/**
 * Obtient les statistiques TTS backend
 */
export async function getTTSStats(): Promise<{ available: boolean; provider: string; voices?: string[] } | null> {
  try {
    const response = await fetch(`${TTS_BACKEND_URL}/stats`);
    if (!response.ok) return null;
    return response.json();
  } catch (err) {
    return null;
  }
}

/**
 * Initialize speech subsystem (browser TTS + speech recognition).
 * Optionally accepts a callback receiving (text, isFinal?) for transcripts.
 * Returns true if SpeechSynthesis API is available.
 */
export function initSpeech(onTranscript?: (text: string, isFinal?: boolean) => void): boolean {
  // Si déjà initialisé, éviter les logs répétés
  if (speechInitialized) {
    return !!window.speechSynthesis;
  }

  console.log('[speech] 🎙️ Initialisation du système de synthèse vocale...');

  const synth = typeof window !== 'undefined' ? window.speechSynthesis : undefined;
  if (synth) {
    try { synth.getVoices(); } catch {}
    try {
      const handler = () => { try { synth.getVoices(); } catch {} };
      // @ts-ignore
      if (typeof synth.onvoiceschanged === 'undefined') {
        try { window.addEventListener('voiceschanged', handler as any); } catch {}
      } else {
        // @ts-ignore
        synth.onvoiceschanged = handler as any;
      }
    } catch {}
    console.log('[speech] ✅ Browser TTS initialisé');
  } else {
    console.warn('[speech] ⚠️ Browser TTS non disponible');
  }

  // Setup speech recognition if available
  try {
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SR) {
      recognition = new SR();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'fr-FR';
      recognition.onresult = (event: any) => {
        try {
          let interim = '';
          let finalText = '';
          for (let i = event.resultIndex; i < event.results.length; i++) {
            const res = event.results[i];
            const txt = res[0]?.transcript || '';
            if (res.isFinal) finalText += txt;
            else interim += txt;
          }
          if (onTranscript) {
            if (interim) onTranscript(interim, false);
            if (finalText) onTranscript(finalText, true);
          }
        } catch {}
      };
      recognition.onerror = () => { /* ignore */ };
      console.log('[speech] ✅ Speech Recognition initialisé');
    }
  } catch {
    console.warn('[speech] ⚠️ Speech Recognition non disponible');
  }

  // Détecter WebView2
  const isWebView2 = !!(window as any).chrome?.webview;
  if (isWebView2) {
    console.log('[speech] 🪟 Mode WebView2 (Visual Studio) détecté');
  }

  speechInitialized = true;
  console.log('[speech] ✅ Système de synthèse vocale prêt');

  return !!synth;
}

/** Start microphone speech recognition */
export async function startMic(): Promise<MediaStream | null> {
  try {
    // Request mic permission/stream (not strictly needed for Web Speech API but useful for UX)
    let stream: MediaStream | null = null;
    try {
      stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    } catch {}
    if (recognition && !micActive) {
      micActive = true;
      try { recognition.start(); } catch {}
    }
    return stream;
  } catch {
    return null;
  }
}

/** Stop microphone speech recognition */
export function stopMic(): void {
  try {
    if (recognition) {
      try { recognition.stop(); } catch {}
    }
  } catch {}
  micActive = false;
}

/** Whether mic recognition is active */
export function isMicActive(): boolean {
  return micActive;
}
