import './lib/avatar-ui';
import { setupInteractionTestListener, blastHorn } from './lib/interaction-test';
import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

// Setup interaction test listeners (for VS communication diagnostics)
setupInteractionTestListener();

// Déclenche la Horn Funesterie au démarrage (exemple)
blastHorn(100);

const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}
