// Avatar UI: écoute les événements de conversation + expose une petite API
// pour synchroniser le GIF avec l'audio TTS.

declare global {
  interface Window {
    A11AvatarUI?: {
      playGifWhileAudio: (
        audio: HTMLAudioElement,
        gifSrc: string,
        durationMs?: number
      ) => void;
    };
  }
}

export function mountA11AvatarUI() {
  // Prevent duplicate mounts (HMR / React StrictMode can call effects twice)
  if (typeof window !== 'undefined' && (window as any).A11AvatarUI) {
    console.log('[A11AvatarUI] already mounted - skipping');
    return;
  }

  // Wait for avatar elements to be present (handles timing/HMR during dev)
  const waitForEls = async (timeout = 2000, interval = 50) => {
    const start = Date.now();
    while (Date.now() - start < timeout) {
      const gif = document.querySelector<HTMLImageElement>('#a11-avatar-gif') || document.querySelector<HTMLImageElement>('#a11-avatar');
      const idle = document.querySelector<HTMLImageElement>('#a11-avatar-idle') || document.querySelector<HTMLImageElement>('#a11-avatar');
      if (gif || idle) return { gif, idle };
      // eslint-disable-next-line no-await-in-loop
      await new Promise((r) => setTimeout(r, interval));
    }
    return { gif: null, idle: null };
  };

  (async () => {
    const { gif, idle } = await waitForEls(2000, 50);
    if (!gif && !idle) {
      console.warn('[A11AvatarUI] #a11-avatar introuvable (after wait)');
      return;
    }

    let gifImg = gif as HTMLImageElement | null;
    const idleImg = idle as HTMLImageElement | null;

    const idleSrc = '/assets/a11_static.png';
    try {
      if (idleImg) {
        idleImg.src = idleSrc;
        idleImg.dataset._static = idleSrc;
      }
      if (!gifImg && idleImg) gifImg = idleImg as HTMLImageElement;
    } catch {}

    // Map to track timeout timers per audio element so we can clear them on stop
    const gifTimeouts = new WeakMap<HTMLAudioElement, number>();
    // Track GIF loop start time and duration on the avatar element
    const GIF_META_KEY = '_a11_gif_meta';

    function playGifWhileAudio(
      audio: HTMLAudioElement,
      gifSrc: string,
      durationMs?: number
    ) {
      console.log('[A11AvatarUI] playGifWhileAudio', { gifSrc, durationMs });

      // clear any previous timeout for this audio
      const prev = gifTimeouts.get(audio);
      if (prev) {
        try { clearTimeout(prev); } catch {};
        gifTimeouts.delete(audio);
      }

      const bust = gifSrc + (gifSrc.includes('?') ? '&' : '?') + 't=' + Date.now();
      gifImg.src = bust;
      // record start time and optional duration for loop-aware stopping
      try {
        gifImg.dataset._a11_gif_start = String(Date.now());
        if (typeof durationMs === 'number' && isFinite(durationMs) && durationMs > 0) {
          gifImg.dataset._a11_gif_duration = String(Math.round(durationMs));
        } else {
          delete gifImg.dataset._a11_gif_duration;
        }
      } catch {}

      audio.currentTime = 0;
      audio.play().catch(console.error);

      // Schedule idle using provided durationMs if available; otherwise fallback to waiting a single loop
      const stop = () => {
        try {
          // clear any previous scheduled idle
          const prevId = gifTimeouts.get(audio);
          if (prevId) {
            try { clearTimeout(prevId); } catch {};
            gifTimeouts.delete(audio);
          }

          const doSetIdle = () => {
            const s = gifImg.dataset._static || idleSrc;
            if (s) gifImg.src = s;
          };

          if (typeof durationMs === 'number' && isFinite(durationMs) && durationMs > 50) {
            // Use server-provided duration to set a single timeout equal to the speech duration
            const id = window.setTimeout(() => {
              try { doSetIdle(); } catch {};
            }, Math.max(50, Math.round(durationMs)));
            gifTimeouts.set(audio, id as unknown as number);
          } else {
            // Fallback: try to use recorded gif duration metadata if present
            const start = parseInt(gifImg.dataset._a11_gif_start || '0', 10) || 0;
            const dur = parseInt(gifImg.dataset._a11_gif_duration || '0', 10) || 0;
            if (dur && start) {
              const elapsed = Date.now() - start;
              const rem = dur - (elapsed % dur);
              const when = Math.max(20, rem);
              const id = window.setTimeout(() => {
                try { doSetIdle(); } catch {};
              }, when);
              gifTimeouts.set(audio, id as unknown as number);
            } else {
              // no duration info — set a conservative default (2s)
              const id = window.setTimeout(() => {
                try { doSetIdle(); } catch {};
              }, 2000);
              gifTimeouts.set(audio, id as unknown as number);
            }
          }
        } catch (e) {
          try {
            const s = gifImg.dataset._static || idleSrc;
            if (s) gifImg.src = s;
          } catch {}
        }

        audio.removeEventListener('ended', stop);
        audio.removeEventListener('pause', stop);
        audio.removeEventListener('error', stop);
      };

      audio.addEventListener('ended', stop);
      audio.addEventListener('pause', stop);
      audio.addEventListener('error', stop);

      if (durationMs && Number.isFinite(durationMs)) {
        setTimeout(() => {
          if (!audio.ended && !audio.paused) {
            console.log('[A11AvatarUI] timeout → force idle');
            gifImg.src = idleSrc;
          }
        }, durationMs + 250);
      }
    }

    window.A11AvatarUI = { playGifWhileAudio };
    console.log('[A11AvatarUI] mounted');
  })();
}
